sql:
SELECT COUNT(*)
FROM analyses
WHERE status = 'completed';

SELECT method_name
FROM methods
WHERE method_id = 10;

external_knowledge:
- 'top performers': refers to users with the highest number of analyses;
- 'specific type of completed analyses': refers to analyses_type = 'required_type' and status = 'completed';
- 'over the past month': refers to analysis_date within the last 30 days from the query execution date.

sql:
SELECT DISTINCT method_id
FROM analyses
WHERE analysis_type = 'initial';

SELECT method_id, MAX(method_version_id)
FROM methods
GROUP BY method_id;

SELECT data_file_id, COUNT(*) AS no_of_versions
FROM data_file_versions
GROUP BY data_file_id;

SELECT * 
FROM analyses
WHERE iter_scale = (SELECT MAX(iter_scale) FROM analyses);
